  inquiryDisputes,
} from '@/db/schema';
import { and, eq, inArray, isNull } from 'drizzle-orm';
import { randomUUID } from 'crypto';
import { getFileFromR2 } from './r2-storage';
import { 
  parsePdfCreditReport, 
